function scrollToSection(id) {
	const el = document.getElementById(id);
	const header = document.getElementById('header');
	if (el && header) {
		const offset = header.offsetHeight;
		window.scrollTo({ top: el.offsetTop - offset, behavior: 'smooth' });
	}
}

function initParticles() {
	const container = document.getElementById('particles');
	if (!container) return;
	for (let i = 0; i < 15; i++) {
		const p = document.createElement('div');
		p.className = 'particle';
		p.style.left = 100 * Math.random() + '%';
		p.style.top = 100 * Math.random() + '%';
		p.style.animationDelay = 20 * Math.random() + 's';
		p.style.animationDuration = 18 + 8 * Math.random() + 's';
		container.appendChild(p);
	}
}

let currentIndex = 0;
const carousel = document.getElementById('carousel');
const indicatorsContainer = document.getElementById('indicators');

function createCarouselItem(item, index) {
	const el = document.createElement('div');
	el.className = 'carousel-item';
	el.dataset.index = index;
	el.innerHTML = `
		<div class="card">
			<div class="card-number">0${item.id}</div>
			<div class="card-image"><img src="${item.image}" alt="${item.title}"></div>
			<h3 class="card-title">${item.title}</h3>
			<p class="card-description">${item.description}</p>
			<a class="card-cta" href="portfolio-${item.id}.html" aria-label="Open ${item.title} details">Explore</a>
		</div>
	`;
	return el;
}

function initCarousel() {
	if (!carousel || !indicatorsContainer) return;
	portfolioData.forEach((item, idx) => {
		carousel.appendChild(createCarouselItem(item, idx));
		const ind = document.createElement('div');
		ind.className = 'indicator';
		if (idx === 0) ind.classList.add('active');
		ind.dataset.index = idx;
		ind.addEventListener('click', () => goToSlide(idx));
		indicatorsContainer.appendChild(ind);
	});
	updateCarousel();
}

function updateCarousel() {
	const items = document.querySelectorAll('.carousel-item');
	const indicators = document.querySelectorAll('.indicator');
	const len = items.length;
	let isDesktop = window.innerWidth > 1024;

	items.forEach((el, idx) => {
		let a = idx - currentIndex;
		if (a > len / 2) a -= len;
		if (a < -len / 2) a += len;

		const o = Math.abs(a);
		const s = a < 0 ? -1 : 1;
		const isMobile = window.innerWidth <= 768;

		let d = 400, l = 600, u = 750;
		if (isMobile) {
			d = 280; l = 420; u = 550;
		} else if (!isDesktop) {
			d = 340; l = 520; u = 650;
		}

		if (o === 0) {
			el.style.transform = 'translate(-50%, -50%) translateZ(0) scale(1)';
			el.style.opacity = '1';
			el.style.zIndex = '10';
		} else if (o === 1) {
			el.style.transform = `translate(-50%, -50%) translateX(${s * d}px) translateZ(-200px) rotateY(${-s * (isMobile ? 25 : 30)}deg) scale(${isMobile ? 0.88 : 0.85})`;
			el.style.opacity = '0.8';
			el.style.zIndex = '5';
		} else if (o === 2) {
			el.style.transform = `translate(-50%, -50%) translateX(${s * l}px) translateZ(-350px) rotateY(${-s * (isMobile ? 35 : 40)}deg) scale(${isMobile ? 0.75 : 0.7})`;
			el.style.opacity = '0.5';
			el.style.zIndex = '3';
		} else if (o === 3) {
			el.style.transform = `translate(-50%, -50%) translateX(${s * u}px) translateZ(-450px) rotateY(${-s * (isMobile ? 40 : 45)}deg) scale(${isMobile ? 0.65 : 0.6})`;
			el.style.opacity = '0.3';
			el.style.zIndex = '2';
		} else {
			el.style.transform = 'translate(-50%, -50%) translateZ(-500px) scale(0.5)';
			el.style.opacity = '0';
			el.style.zIndex = '1';
		}

		el.style.transition = 'all 0.8s cubic-bezier(0.4, 0.0, 0.2, 1)';
	});

	indicators.forEach((ind, i) => {
		ind.classList.toggle('active', i === currentIndex);
	});
}

function nextSlide() {
	currentIndex = (currentIndex + 1) % portfolioData.length;
	updateCarousel();
}

function prevSlide() {
	currentIndex = (currentIndex - 1 + portfolioData.length) % portfolioData.length;
	updateCarousel();
}

function goToSlide(i) {
	currentIndex = i;
	updateCarousel();
}

const nextBtn = document.getElementById('nextBtn');
const prevBtn = document.getElementById('prevBtn');
if (nextBtn) nextBtn.addEventListener('click', nextSlide);
if (prevBtn) prevBtn.addEventListener('click', prevSlide);

if (carousel && indicatorsContainer) setInterval(nextSlide, 5000);

document.addEventListener('keydown', (ev) => {
	const certModal = document.getElementById('certLightboxModal');
	if (certModal && certModal.classList.contains('active')) return;
	if (!carousel || !indicatorsContainer) return;
	if (ev.key === 'ArrowLeft') prevSlide();
	if (ev.key === 'ArrowRight') nextSlide();
});

let resizeTimeout;
window.addEventListener('resize', () => {
	clearTimeout(resizeTimeout);
	resizeTimeout = setTimeout(() => { updateCarousel(); }, 250);
});

if (carousel && indicatorsContainer) initCarousel();
initParticles();

const menuToggle = document.getElementById('menuToggle');
const navMenu = document.getElementById('navMenu');
if (menuToggle && navMenu) {
	menuToggle.addEventListener('click', () => {
		navMenu.classList.toggle('active');
		menuToggle.classList.toggle('active');
	});
}

const headerEl = document.getElementById('header');
window.addEventListener('scroll', () => {
	if (!headerEl) return;
	if (window.scrollY > 100) headerEl.classList.add('scrolled');
	else headerEl.classList.remove('scrolled');
});

const sections = document.querySelectorAll('section[id]');
const navLinks = document.querySelectorAll('.nav-link');

navLinks.forEach((link) => {
	link.addEventListener('click', (ev) => {
		const href = link.getAttribute('href');
		if (href && href.startsWith('#')) {
			ev.preventDefault();
			const target = document.getElementById(href.substring(1));
			if (target && headerEl) {
				const offset = headerEl.offsetHeight;
				window.scrollTo({ top: target.offsetTop - offset, behavior: 'smooth' });
				if (navMenu && menuToggle) {
					navMenu.classList.remove('active');
					menuToggle.classList.remove('active');
				}
			}
		} else {
			if (navMenu && menuToggle) {
				navMenu.classList.remove('active');
				menuToggle.classList.remove('active');
			}
		}
	});
});

window.addEventListener('scroll', () => {
	const pos = window.scrollY + 100;
	sections.forEach((sec) => {
		const top = sec.offsetTop;
		if (pos >= top && pos < top + sec.offsetHeight) {
			const id = sec.getAttribute('id');
			navLinks.forEach((lnk) => {
				const href = lnk.getAttribute('href').substring(1);
				lnk.classList.toggle('active', href === id);
			});
		}
	});
});

document.querySelectorAll('.stat-number').forEach((el) => {
	const target = el.dataset.target;
	if (target) el.textContent = target;
});

const contactForm = document.getElementById('contactForm');
if (contactForm) {
	contactForm.addEventListener('submit', async (ev) => {
		ev.preventDefault();
		const btn = contactForm.querySelector('.submit-btn');
		if (!btn) return;
		const originalText = btn.textContent;
		btn.textContent = 'Sending...';
		btn.disabled = true;
		try {
			const fd = new FormData(contactForm);
			const payload = {
				name: fd.get('name') || '',
				email: fd.get('email') || '',
				subject: fd.get('subject') || '',
				message: fd.get('message') || ''
			};
			const res = await fetch('/api/send-email', {
				method: 'POST',
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify(payload)
			});
			if (res.ok) {
				const data = await res.json();
				alert(`✅ Thank you ${payload.name}! Your message has been sent successfully. I'll respond within 24 hours.`);
				contactForm.reset();
			} else {
				const err = await res.json();
				alert('❌ Failed to send message: ' + (err.error || 'Unknown error'));
			}
		} catch (err) {
			console.error('Form submission error:', err);
			alert('❌ Error: ' + err.message);
		} finally {
			btn.textContent = originalText;
			btn.disabled = false;
		}
	});
}

(function initLoader() {
	const loader = document.getElementById('loader');
	if (!loader) return;
	const firstLoad = !sessionStorage.getItem('pageLoaded');
	if (!firstLoad) {
		loader.classList.add('hidden');
		return;
	}
	sessionStorage.setItem('pageLoaded', 'true');

	const line1 = document.getElementById('line1');
	const line2 = document.getElementById('line2');
	const line3 = document.getElementById('line3');
	if (!line1 || !line2 || !line3) return;

	function typeText(el, text, delay = 50) {
		return new Promise((resolve) => {
			let i = 0;
			el.textContent = '';
			const t = setInterval(() => {
				if (i < text.length) {
					el.textContent += text.charAt(i);
					i++;
				} else {
					clearInterval(t);
					resolve();
				}
			}, delay);
		});
	}

	let started = false;
	let loaded = false;
	let blinkTimer = null;

	const run = async () => {
		await typeText(line1, 'Trace: Locating Server @8.8.xx.xx', 40);
		await new Promise((r) => setTimeout(r, 200));
		await typeText(line2, 'Status: [SCANNING_PORTS]..', 40);
		await new Promise((r) => setTimeout(r, 200));
		await typeText(line3, 'Access: PENDING_', 40);

		if (!blinkTimer) {
			let flag = true;
			blinkTimer = setInterval(() => {
				line3.classList.remove('pending-red', 'pending-green');
				line3.classList.add(flag ? 'pending-red' : 'pending-green');
				flag = !flag;
			}, 500);
		}

		started = true;
		if (started && loaded) finish();
	};

	function finish() {
		if (blinkTimer) {
			clearInterval(blinkTimer);
			blinkTimer = null;
		}
		line3.classList.remove('pending-red', 'pending-green');
		line3.classList.add('success');
		line3.textContent = 'Access: SUCCESS_';
		setTimeout(() => loader.classList.add('hidden'), 400);
	}

	run();
	window.addEventListener('load', () => {
		loaded = true;
		if (started) finish();
	});
})();

window.addEventListener('scroll', () => {
	const hero = document.querySelector('.hero');
	if (hero) hero.style.transform = `translateY(${0.5 * window.pageYOffset}px)`;
});

window.addEventListener('load', () => {
	const v = sessionStorage.getItem('pageLoaded');
	if (!v) sessionStorage.setItem('pageLoaded', 'true');
});
